  ('social-worker-moex-03992', 'social-worker', 'social-worker-moex-112-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關社會救助法第15條中就業服務之規定，下列何者錯誤？', '["給予有工作能力者相關就業服務、職業訓練或以工代賑", "視需要給予創業貸款利息補貼、交通補助、臨時托育及日間照顧津貼等補助", "因就業而增加之收入，得全數免列入家庭總收入計算", "不願接受服務或接受後不願工作者，主管機關不予扶助"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "a126b5b456bb", "answer_pdf_sha1": "c9536bdc9497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03993', 'social-worker', 'social-worker-moex-112-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '社會救助法第5條之3對有無具備工作能力的認定，下列何者錯誤？', '["身心障礙者均視為無工作能力", "具有工作能力之年齡條件認定範圍為16歲以上未滿65歲", "獨自撫養6歲以下之直系血親卑親屬致不能工作者，視為無工作能力", "受監護宣告者視為無工作能力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "a126b5b456bb", "answer_pdf_sha1": "c9536bdc9497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03994', 'social-worker', 'social-worker-moex-112-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依社會工作師法第18條規定，社會工作師及專科社會工作師執業，應接受繼續教育，並於一定期 間內完成繼續教育的證明文件，報請主管機關備查，所稱一定期限係指幾年？', '["3年", "4年", "5年", "6年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "a126b5b456bb", "answer_pdf_sha1": "c9536bdc9497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03995', 'social-worker', 'social-worker-moex-112-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依兒童及少年性剝削防制條例第 19 條的條文內容，法院於相關事證調查完竣後 7 日內對被害人 之裁定，下列何者錯誤？', '["認無安置必要者，應不付安置，並交付父母、監護人或其他適當之人", "被害人為無合法有效之停（居）留許可之外國人、大陸地區人民、香港、澳門居民或臺灣地區 無戶籍國民，逕行遣返", "認為有安置必要者，應裁定安置於直轄市、縣（市）主管機關自行設立或委託之兒童及少年福 利機構、寄養家庭、中途學校或其他適當之醫療、教育機構期間不得逾2年", "其他適當之處遇方式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "a126b5b456bb", "answer_pdf_sha1": "c9536bdc9497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03996', 'social-worker', 'social-worker-moex-112-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依公益勸募條例第6條規定，各級政府機關（構）辦理勸募時，該政府機關（構）有上級機關者， 應於年度終了後最遲幾個月內，將辦理情形函報上級機關備查？', '["1個月", "2個月", "3個月", "5個月"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "a126b5b456bb", "answer_pdf_sha1": "c9536bdc9497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03997', 'social-worker', 'social-worker-moex-112-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '按特殊境遇家庭扶助條例第11條規定，申請法律訴訟補助，應於事實發生後最遲幾個月內向戶籍 所在地之主管機關申請？', '["1個月", "2個月", "3個月", "6個月"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "a126b5b456bb", "answer_pdf_sha1": "c9536bdc9497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03998', 'social-worker', 'social-worker-moex-112-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據性侵害犯罪防治法第4條規定，下列何者應為社政主管機關之權責事項？', '["性侵害被害人之保護扶助工作", "性侵害防治教育、性侵害被害人及其子女就學權益之維護等相關事宜", "性侵害犯罪之偵查相關事宜", "性侵害被害人人身安全之維護相關事宜"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "a126b5b456bb", "answer_pdf_sha1": "c9536bdc9497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03999', 'social-worker', 'social-worker-moex-112-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據性侵害犯罪防治法，當被害人係兒童及少年或心智障礙者，於司法偵查或審判時之權益規定， 下列敘述何者錯誤？', '["被害人之法定代理人、配偶、直系或三親等內旁系血親、家長、家屬得於偵查或審判中，陪同 被害人在場，並得陳述意見", "偵查或審判中，直轄市、縣（市）主管機關得不指派社工人員陪同在場", "兒童或心智障礙之性侵害被害人於偵查或審判階段，經司法警察、司法警察官、檢察事務官、 檢察官或法官認有必要時，應由具相關專業人士在場協助詢（訊）問", "專業人士於協助詢（訊）問時，司法警察、司法警察官、檢察事務官、檢察官或法官，得透過 單面鏡、聲音影像相互傳送之科技設備，或適當隔離措施為之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "a126b5b456bb", "answer_pdf_sha1": "c9536bdc9497", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
